import {useEffect} from 'react';

/**
 * iOS WKWebView/Safari 에서 input/textarea/select 에 focus 가 잡힐 때
 * 해당 요소를 화면 중앙으로 즉시 스크롤한다.
 *
 * - focus 즉시 스크롤(키보드 슬라이드업과 병렬 진행) → 자연스러운 즉시감
 * - 키보드가 완전히 올라온 직후(visualViewport resize) 한 번 더 보정
 *
 * 안드로이드는 OS 가 자동으로 처리해주므로 동작하지 않음.
 *
 * 사용 예:
 *   const Component = () => {
 *       useIosInputAutoScroll();
 *       return <input ... />;
 *   };
 */
const isIOS = (): boolean => {
    if (typeof navigator === 'undefined' || typeof window === 'undefined') return false;
    const ua = navigator.userAgent;
    const isIPadOS = ua.includes('Macintosh') && 'ontouchend' in document;
    return /iPad|iPhone|iPod/.test(ua) || isIPadOS;
};

const FOCUSABLE_TAGS = new Set(['INPUT', 'TEXTAREA', 'SELECT']);

const scrollIntoCenter = (el: HTMLElement) => {
    try {
        // behavior: 'auto' = 즉시 스냅 (네이티브 iOS 동작과 동일)
        el.scrollIntoView({block: 'center', behavior: 'auto'});
    } catch {
        el.scrollIntoView();
    }
};

export function useIosInputAutoScroll(): void {
    useEffect(() => {
        if (!isIOS()) return;
        if (typeof document === 'undefined') return;

        let activeElement: HTMLElement | null = null;

        const handleFocusIn = (e: FocusEvent) => {
            const target = e.target as HTMLElement | null;
            if (!target || !FOCUSABLE_TAGS.has(target.tagName)) return;

            if (target instanceof HTMLInputElement) {
                if (target.type === 'hidden' || target.readOnly) return;
            }

            activeElement = target;
            // 키보드가 올라오기 전에 즉시 스크롤 (지연 없음)
            scrollIntoCenter(target);
        };

        const handleFocusOut = () => {
            activeElement = null;
        };

        const handleViewportResize = () => {
            // 키보드 애니메이션이 끝난 직후 한 번 더 보정
            // (focus 시 스크롤한 위치가 키보드에 의해 어긋났을 경우만 효과 있음)
            if (activeElement && document.activeElement === activeElement) {
                scrollIntoCenter(activeElement);
            }
        };

        document.addEventListener('focusin', handleFocusIn);
        document.addEventListener('focusout', handleFocusOut);
        window.visualViewport?.addEventListener('resize', handleViewportResize);

        return () => {
            document.removeEventListener('focusin', handleFocusIn);
            document.removeEventListener('focusout', handleFocusOut);
            window.visualViewport?.removeEventListener('resize', handleViewportResize);
        };
    }, []);
}

export default useIosInputAutoScroll;
